8603	\begin{lemma}
8604	[Ext-vanishing forces the coyoneda right-derived object to vanish]
8605	  \label{lem:isZero_coyoneda_rightDerived_of_forall_ext_eq_zero}
8606	  \lean{AlgebraicGeometry.isZero_coyoneda_rightDerived_of_forall_ext_eq_zero,
8607	    AlgebraicGeometry.preadditiveCoyoneda_mapHomologicalComplex_d_apply}
8608	  \uses{lem:ext_homcomplex_mathlib, lem:right_derived_injective_resolution}
8609	  Let \(\mathcal{C}\) be an abelian category with enough injectives, let \(P, H \in \mathcal{C}\), and
8610	  let \(q \geq 1\). If every class \(e \in \operatorname{Ext}^q(P, H)\) is zero, then the right-derived
8611	  object of the covariant hom-functor vanishes at \(H\):
8612	  \[
8613	    \bigl((\operatorname{Hom}(P, -)).\mathrm{rightDerived}\,q\bigr)(H) \;\text{ is a zero object.}
8614	  \]
8615	\end{lemma}
8616	\begin{proof}
8617	  \uses{lem:ext_homcomplex_mathlib, lem:right_derived_injective_resolution}
8618	  Choose an injective resolution \(H \to \mathcal{I}^\bullet\). By the right-derived-object comparison
8619	  (Lemma~\ref{lem:right_derived_injective_resolution}) the value
8620	  \(((\operatorname{Hom}(P,-)).\mathrm{rightDerived}\,q)(H)\) is identified with the degree-\(q\)
8621	  homology of the \(\operatorname{Hom}\)-cochain complex \(n \mapsto (P \to \mathcal{I}^n)\), whose
8622	  differential is post-composition with the differential of \(\mathcal{I}^\bullet\). A degree-\(q\)
8623	  cocycle is a map \(f : P \to \mathcal{I}^q\) with \(f \circ d = 0\), and by the
8624	  Ext--Hom-complex identification (Lemma~\ref{lem:ext_homcomplex_mathlib}) such an \(f\) is a
8625	  coboundary exactly when its class \(\operatorname{extMk} f \in \operatorname{Ext}^q(P, H)\) vanishes.
8626	  The hypothesis makes every such class zero, so every \(q\)-cocycle is a coboundary; the homology at
8627	  \(q\) is therefore zero and the right-derived object is a zero object.
8628	\end{proof}
