8632	\leanok
8633	[An isomorphism in the first Ext-argument transfers subsingletons]
8634	  \label{lem:subsingleton_ext_of_iso_fst}
8635	  \lean{AlgebraicGeometry.subsingleton_ext_of_iso_fst}
8636	  \uses{lem:ext_homcomplex_mathlib}
8637	  Let \(\mathcal{C}\) be an abelian category with an Ext-theory, \(\varphi : A \cong B\) an
8638	  isomorphism, \(Y \in \mathcal{C}\) an object and \(q\) a degree. If \(\operatorname{Ext}^q(B, Y)\)
8639	  is a subsingleton (has at most one element), then so is \(\operatorname{Ext}^q(A, Y)\).
8640	\end{lemma}
8641	\begin{proof}
8642	  \uses{lem:ext_homcomplex_mathlib}
8643	  Ext is contravariant in its first argument. For any \(z \in \operatorname{Ext}^q(A, Y)\),
8644	  associativity of Yoneda composition with the degree-\(0\) classes of \(\varphi\) gives
8645	  \[
8646	    z = \operatorname{mk}_0(\varphi.\mathrm{hom}) \circ \bigl(\operatorname{mk}_0(\varphi.\mathrm{inv})
8647	      \circ z\bigr),
8648	  \]
8649	  using \(\varphi.\mathrm{inv} \circ \varphi.\mathrm{hom} = \mathrm{id}\) and the identity law
8650	  \(\operatorname{mk}_0(\mathrm{id}) \circ z = z\). The inner factor
8651	  \(\operatorname{mk}_0(\varphi.\mathrm{inv}) \circ z\) lives in the subsingleton
8652	  \(\operatorname{Ext}^q(B, Y)\), hence equals \(0\); composing with \(0\) gives \(z = 0\). Since every
8653	  element is \(0\), \(\operatorname{Ext}^q(A, Y)\) is a subsingleton.
8654	\end{proof}
