8658	\leanok
8659	[Injective resolutions provide enough injectives]
8660	  \label{lem:enoughInjectives_of_hasInjectiveResolutions}
8661	  \lean{AlgebraicGeometry.enoughInjectives_of_hasInjectiveResolutions}
8662	  \uses{lem:right_derived_injective_resolution}
8663	  An abelian category equipped with chosen injective resolutions has enough injectives: every object
8664	  admits a monomorphism into an injective object.
8665	\end{lemma}
8666	\begin{proof}
8667	  \uses{lem:right_derived_injective_resolution}
8668	  Given an object \(X\), take its chosen injective resolution \(X \to \mathcal{I}^\bullet\). The
8669	  degree-\(0\) term \(\mathcal{I}^0\) is injective and the resolution's unit \(X \to \mathcal{I}^0\) is
8670	  a monomorphism, so it is an injective presentation of \(X\). As every object has one, the category
8671	  has enough injectives.
8672	\end{proof}
